// Get range from webhook query params
const range = $('Webhook Trigger').first().json.query?.range || '24h';

const rangeMs = {
  '24h': 24 * 60 * 60 * 1000,
  '7d': 7 * 24 * 60 * 60 * 1000,
  '30d': 30 * 24 * 60 * 60 * 1000,
}[range] || 24 * 60 * 60 * 1000;

const cutoff = new Date(Date.now() - rangeMs);

// Build workflow name map from Fetch Workflows response
const wfListData = $('Fetch Workflows').first().json;
const wfNameMap = {};
if (wfListData && wfListData.data) {
  for (const wf of wfListData.data) {
    wfNameMap[wf.id] = wf.name;
  }
}

// Parse executions from API response
const apiData = $('Fetch Executions').first().json;
const allExecs = apiData.data || [];

// Filter by time range
const execs = allExecs.filter(e => new Date(e.startedAt || e.stoppedAt) >= cutoff);

// Build time series buckets
const bucketCount = range === '24h' ? 24 : range === '7d' ? 7 : 30;
const bucketMs = rangeMs / bucketCount;
const timeSeries = [];

for (let i = 0; i < bucketCount; i++) {
  const bucketStart = new Date(Date.now() - rangeMs + i * bucketMs);
  const bucketEnd = new Date(bucketStart.getTime() + bucketMs);
  const bucketExecs = execs.filter(e => {
    const t = new Date(e.startedAt || e.stoppedAt);
    return t >= bucketStart && t < bucketEnd;
  });
  const label = range === '24h'
    ? bucketStart.toLocaleTimeString('cs-CZ', { hour: '2-digit', minute: '2-digit' })
    : bucketStart.toLocaleDateString('cs-CZ', { day: 'numeric', month: 'numeric' });
  timeSeries.push({
    bucket: label,
    success: bucketExecs.filter(e => e.status === 'success').length,
    failure: bucketExecs.filter(e => e.status === 'error').length,
  });
}

// Per-workflow stats
const wfMap = {};
for (const e of execs) {
  const name = wfNameMap[e.workflowId] || e.workflowData?.name || 'Unknown';
  if (!wfMap[name]) wfMap[name] = { name, success: 0, failure: 0, totalDuration: 0, lastFailure: null };
  if (e.status === 'success') wfMap[name].success++;
  else wfMap[name].failure++;
  if (e.startedAt && e.stoppedAt) {
    wfMap[name].totalDuration += new Date(e.stoppedAt).getTime() - new Date(e.startedAt).getTime();
  }
  if (e.status === 'error' && (!wfMap[name].lastFailure || e.stoppedAt > wfMap[name].lastFailure)) {
    wfMap[name].lastFailure = e.stoppedAt;
  }
}

const workflows = Object.values(wfMap).map(w => {
  const total = w.success + w.failure;
  return {
    name: w.name,
    totalRuns: total,
    successCount: w.success,
    failureCount: w.failure,
    successRate: total > 0 ? (w.success / total) * 100 : 100,
    avgDurationMs: total > 0 ? Math.round(w.totalDuration / total) : 0,
    lastFailure: w.lastFailure,
  };
}).sort((a, b) => a.successRate - b.successRate);

// Recent failures (last 10)
const recentFailures = execs
  .filter(e => e.status === 'error')
  .sort((a, b) => new Date(b.stoppedAt || b.startedAt).getTime() - new Date(a.stoppedAt || a.startedAt).getTime())
  .slice(0, 10)
  .map(e => ({
    workflowName: wfNameMap[e.workflowId] || 'Unknown',
    error: (e.data?.resultData?.error?.message || 'Unknown error').substring(0, 500),
    timestamp: e.stoppedAt || e.startedAt,
  }));

return [{ json: { timeSeries, workflows, recentFailures } }];
